// Set path to watchout-config.json (edit this path if needed)
msg.filename = msg.payload || '/config/watchout-config.json';
return msg;

// Parse watchout-config.json
let cfg = {};
try {
    cfg = JSON.parse(msg.payload);
} catch(e) {
    node.warn('[Watchout] watchout-config.json parse error, using defaults: ' + e.message);
}
cfg.host        = cfg.host        || 'localhost';
cfg.port        = cfg.port        || 3019;
cfg.mappingFile = cfg.mappingFile || '/data/timeline-mapping.json';
flow.set('watchout_config', cfg);
node.status({ fill: 'green', shape: 'dot', text: 'Config: ' + cfg.host + ':' + cfg.port });
// Feed filename forward to read mapping file
msg.filename = cfg.mappingFile;
return msg;

// Config file missing — create defaults
const defaultCfg = {
    host: 'localhost',
    port: 3019,
    mappingFile: '/data/timeline-mapping.json'
};
flow.set('watchout_config', defaultCfg);
node.warn('[Watchout] watchout-config.json not found — writing defaults');
msg.filename = '/config/watchout-config.json';
msg.payload  = JSON.stringify(defaultCfg, null, 2);
return msg;

// After writing default config, continue to mapping read
const cfg = flow.get('watchout_config') || {};
msg.filename = cfg.mappingFile || '/data/watchout/timeline-mapping.json';
return msg;

// Parse timeline-mapping.json
let mapping = {};
try {
    const raw = JSON.parse(msg.payload);
    mapping = raw.mapping || raw || {};
} catch(e) {
    node.warn('[Watchout] timeline-mapping.json parse error, starting empty: ' + e.message);
}
flow.set('watchout_mapping', mapping);
flow.set('watchout_pending', null);
const count = Object.keys(mapping).length;
node.status({ fill: 'green', shape: 'dot', text: 'Mapping loaded: ' + count + ' timelines' });
return null;

// Mapping file missing — start with empty mapping
flow.set('watchout_mapping', {});
flow.set('watchout_pending', null);
node.warn('[Watchout] timeline-mapping.json not found — starting with empty mapping');
return null;

// Build the HTTP GET request for /v0/timelines
const cfg  = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
msg.method  = 'GET';
msg.url     = 'http://' + host + ':' + port + '/v0/timelines';
msg.headers = { 'Content-Type': 'application/json' };
return msg;

// Prepare mapping JSON for file write
const pending = flow.get('watchout_pending');
if (!pending) {
    node.send({ payload: { status: 'nothing_pending' }, topic: 'watchout/confirm' });
    return null;
}

// Update flow context immediately
flow.set('watchout_mapping', pending);
flow.set('watchout_pending', null);

// Prepare file write
const cfg = flow.get('watchout_config') || {};
msg.filename = cfg.mappingFile || '/data/watchout/timeline-mapping.json';
msg.payload  = JSON.stringify({ mapping: pending, lastSaved: new Date().toISOString() }, null, 2);
msg._pendingMapping = pending;
msg._savedAt = new Date().toISOString();
return msg;

// Confirm & Save completed
const mapping = msg._pendingMapping || flow.get('watchout_mapping') || {};
node.status({ fill: 'green', shape: 'dot', text: 'Saved: ' + Object.keys(mapping).length + ' timelines' });
node.send({
    payload: {
        status:  'saved',
        mapping: mapping,
        savedAt: msg._savedAt || new Date().toISOString()
    },
    topic: 'watchout/confirm'
});
return null;

// Cancel pending discovery
flow.set('watchout_pending', null);
node.send({ payload: { status: 'cancelled' }, topic: 'watchout/cancel' });
return null;

// Validate input and build HTTP request for timeline control.
// Output 1: valid command  → HTTP Request node
// Output 2: unknown command → HTTP Response (error)

const cfg     = flow.get('watchout_config') || {};
const host    = cfg.host || 'localhost';
const port    = cfg.port || 3019;
const baseUrl = 'http://' + host + ':' + port;

const input   = msg.payload || {};
const command = input.command;
const mapping = flow.get('watchout_mapping') || {};

function resolveTimelineId(contentId) {
    return (contentId in mapping) ? mapping[contentId] : String(contentId);
}

msg._command = command;
msg.headers  = { 'Content-Type': 'application/json' };

switch (command) {
    case 'start':
    case 'stop':
    case 'pause': {
        const timelineId   = resolveTimelineId(input.contentId);
        msg._timelineId    = timelineId;
        msg.method         = 'POST';
        const action       = (command === 'start') ? 'play' : command;
        msg.url            = baseUrl + '/v0/timelines/' + timelineId + '/' + action;
        msg.payload        = null;
        return [msg, null];
    }
    case 'setVar': {
        msg.method  = 'PUT';
        msg.url     = baseUrl + '/v0/vars/' + encodeURIComponent(input.varName);
        msg.payload = { value: input.varValue };
        return [msg, null];
    }
    case 'getState': {
        msg.method  = 'GET';
        msg.url     = baseUrl + '/v0/state';
        msg.payload = null;
        return [msg, null];
    }
    default: {
        msg.statusCode = 400;
        msg.payload    = JSON.stringify({ success: false, error: 'Unknown command: ' + command });
        return [null, msg];
    }
}

// Build the SSE endpoint URL from flow config and trigger the SSE client
const cfg  = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
msg.url     = 'http://' + host + ':' + port + '/v0/events';
msg.headers = { 'Accept': 'text/event-stream', 'Cache-Control': 'no-cache' };
flow.set('watchout_sse_status', 'connecting');
return msg;

// Only poll Watchout state when SSE is not connected (fallback mode)
if (flow.get('watchout_sse_status') === 'connected') {
    return null;
}

const cfg  = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
msg.method  = 'GET';
msg.url     = 'http://' + host + ':' + port + '/v0/state';
msg.headers = { 'Content-Type': 'application/json' };
return msg;

// Parse GET /v0/timelines response and build diff

if (msg.statusCode !== 200) {
    msg.payload = { status: 'error', error: 'Watchout returned HTTP ' + (msg.statusCode || 'unknown') };
    return msg;
}

function parseTimelineName(name) {
    if (!name || name.startsWith('_')) return null;
    return name.trim().toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '');
}

function compareMapping(oldMap, newMap) {
    const oldKeys = Object.keys(oldMap);
    const newKeys = Object.keys(newMap);
    return {
        removed:   oldKeys.filter(k => !(k in newMap)),
        added:     newKeys.filter(k => !(k in oldMap)),
        unchanged: oldKeys.filter(k => (k in newMap) && oldMap[k] === newMap[k]),
        changed:   oldKeys.filter(k => (k in newMap) && oldMap[k] !== newMap[k]),
    };
}

function formatDiff(diff) {
    const lines = [];
    diff.removed.forEach(n   => lines.push("REMOVED  : Timeline '" + n + "' no longer exists"));
    diff.added.forEach(n     => lines.push("ADDED    : New timeline '" + n + "' discovered"));
    diff.changed.forEach(n   => lines.push("CHANGED  : Timeline '" + n + "' ID has changed"));
    diff.unchanged.forEach(n   => lines.push("OK       : '" + n + "'"));
    return lines;
}

const timelines = Array.isArray(msg.payload) ? msg.payload : [];

const newMapping = {};
timelines.forEach(tl => {
    const contentId = parseTimelineName(tl.name);
    if (contentId) newMapping[contentId] = String(tl.id);
});

const storedMapping = flow.get('watchout_mapping') || {};
const diff     = compareMapping(storedMapping, newMapping);
const diffLines = formatDiff(diff);

flow.set('watchout_pending', newMapping);

const count = Object.keys(newMapping).length;
node.status({ fill: 'green', shape: 'dot', text: 'Discovered: ' + count + ' timelines' });

msg.payload = { status: 'discovered', count, diffLines, newMapping, diff };
return msg;

// Normalize the Watchout API response into a uniform JSON object
const command    = msg._command;
const timelineId = msg._timelineId;
const statusCode = msg.statusCode || 200;

msg.payload    = JSON.stringify({
    success:    statusCode < 300,
    command:    command,
    timelineId: timelineId,
    statusCode: statusCode,
    body:       msg.payload
});
msg.statusCode = 200;
msg.headers    = { 'Content-Type': 'application/json' };
return msg;

// Process an incoming SSE event from the Watchout SSE client node.
// msg.payload = event data (auto-parsed JSON if possible)
// msg.event   = event type string

const wasConnected = flow.get('watchout_sse_status') === 'connected';

const event = {
    type: msg.event || 'message',
    data: msg.payload
};

flow.set('watchout_state',      event.data || event);
flow.set('watchout_sse_status', 'connected');

// Output 1: state event for Live State UI
const stateMsg  = { payload: event, topic: 'watchout/state' };

// Output 2: SSE status update (only send once on initial connect)
const statusMsg = wasConnected ? null
    : { payload: { status: 'sse_connected' } };

node.send([stateMsg, statusMsg]);
return null;

// Handle SSE connection errors / disconnects
flow.set('watchout_sse_status', 'error');
const errMsg = (msg.error && msg.error.message) ? msg.error.message : String(msg.error || 'SSE error');
node.send({ payload: { status: 'sse_error', message: errMsg } });
return null;

// Handle the GET /v0/state poll response
const statusCode = msg.statusCode || 200;
if (statusCode !== 200) {
    node.warn('[Watchout Poll] HTTP ' + statusCode);
    return null;
}

const state = msg.payload;
flow.set('watchout_state', state);

node.send({ payload: { type: 'poll', data: state }, topic: 'watchout/state' });
return null;
